const errors = [];
for (const field of ['run_id', 'task_id', 'goal', 'criteria', 'iteration', 'instruction', 'status']) {
  if ($json[field] === undefined || $json[field] === null || $json[field] === '') {
    errors.push(`${field} is required`);
  }
}
if (!Array.isArray($json.criteria) || $json.criteria.length === 0) {
  errors.push('criteria must contain at least one item');
}
return [{ json: { ...$json, validation_errors: errors } }];

const input = $json;

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const requestedProviderMode =
  typeof input.provider_mode === 'string' && input.provider_mode.trim()
    ? input.provider_mode.trim()
    : typeof input.agent_mode === 'string' && input.agent_mode.trim()
      ? input.agent_mode.trim()
      : typeof context.agent_mode === 'string' && context.agent_mode.trim()
        ? context.agent_mode.trim()
        : 'mock';

const supportedModes = ['mock', 'dry-run'];
const providerMode = supportedModes.includes(requestedProviderMode)
  ? requestedProviderMode
  : 'mock';
const modeWarnings = supportedModes.includes(requestedProviderMode)
  ? []
  : ['unknown provider mode fallback to mock'];

return [
  {
    json: {
      ...input,
      context: {
        ...context,
        agent_mode: providerMode,
      },
      prompt_reference: 'src/prompts/subagent_prompt.md',
      prompt_contract: {
        output: 'result.schema.json',
        format: 'json_only',
      },
      requested_provider_mode: requestedProviderMode,
      provider_mode: providerMode,
      agent_mode: providerMode,
      mode_warnings: modeWarnings,
    },
  },
];

if (($json.validation_errors || []).length > 0) {
  return [{
    json: {
      run_id: $json.run_id || 'unknown',
      task_id: $json.task_id || 'unknown',
      status: 'failed',
      summary: 'Task validation failed before execution.',
      artifacts: [],
      known_issues: $json.validation_errors,
      evidence: ($json.criteria || ['task payload']).map((criterion) => ({
        criterion,
        status: 'fail',
        detail: 'Executor could not run because the task payload was invalid.'
      })),
      next_action_suggestion: 'Fix the task payload and retry.',
      error: {
        code: 'TASK_VALIDATION_FAILED',
        message: $json.validation_errors.join('; ')
      }
    }
  }];
}

const evidence = ($json.criteria || []).map((criterion, index) => ({
  criterion,
  status: index < 2 ? 'pass' : 'fail',
  detail: index < 2
    ? `Mock executor produced evidence for criterion ${index + 1}.`
    : `Mock executor intentionally leaves criterion ${index + 1} unresolved.`
}));

return [{
  json: {
    run_id: $json.run_id,
    task_id: $json.task_id,
    status: evidence.every((item) => item.status === 'pass') ? 'completed' : 'partial',
    summary: 'Mock executor completed one bounded task iteration.',
    artifacts: ['docs/WORKFLOW_DESIGN.md'],
    known_issues: evidence.filter((item) => item.status !== 'pass').map((item) => item.detail),
    evidence,
    next_action_suggestion: 'Run Criteria Checker to assess whether another iteration is required.',
    error: null
  }
}];

const criteria = Array.isArray($json.criteria) ? $json.criteria : [];
const riskLevel = ['low', 'medium', 'high'].includes($json.risk_level)
  ? $json.risk_level
  : 'low';
const validationErrors = Array.isArray($json.validation_errors)
  ? $json.validation_errors
  : [];

const intendedActions = [
  'Review the goal and success criteria.',
  'Prepare a bounded implementation plan.',
  'Identify validation evidence required before any real execution.'
];

const dryRunPlan = {
  goal: $json.goal || '',
  intended_actions: validationErrors.length > 0 ? [] : intendedActions,
  risk_summary: validationErrors.length > 0
    ? 'Dry-run could not generate a safe plan because the task payload failed validation.'
    : 'Dry-run only. Proposed work remains unexecuted. Risk level: ' + riskLevel + '.',
  requires_human_approval_before_real_run: true
};

if (validationErrors.length > 0) {
  return [{
    json: {
      run_id: $json.run_id || 'unknown',
      task_id: $json.task_id || 'unknown',
      status: 'failed',
      summary: 'Task validation failed before dry-run planning.',
      artifacts: [],
      known_issues: validationErrors,
      evidence: (criteria.length > 0 ? criteria : ['task payload']).map((criterion) => ({
        criterion,
        status: 'fail',
        detail: 'Dry-run could not proceed because the task payload was invalid.'
      })),
      dry_run_plan: dryRunPlan,
      provider: {
        mode: 'dry-run',
        name: 'dry-run-provider',
        model: null,
        request_id: null,
        latency_ms: 0
      },
      safety: {
        risk_level: riskLevel,
        requires_human_approval: true,
        approved: false,
        blocked_reason: 'dry-run mode does not execute real actions'
      },
      next_action_suggestion: 'Fix the task payload and retry the dry-run.',
      error: {
        code: 'TASK_VALIDATION_FAILED',
        message: validationErrors.join('; ')
      }
    }
  }];
}

return [{
  json: {
    run_id: $json.run_id,
    task_id: $json.task_id,
    status: 'needs_review',
    summary: 'Dry-run plan generated. No real action was executed.',
    artifacts: [],
    known_issues: [],
    evidence: criteria.map((criterion) => ({
      criterion,
      status: 'unknown',
      detail: 'Dry-run generated a plan but did not execute real work.'
    })),
    dry_run_plan: dryRunPlan,
    provider: {
      mode: 'dry-run',
      name: 'dry-run-provider',
      model: null,
      request_id: null,
      latency_ms: 0
    },
    safety: {
      risk_level: riskLevel,
      requires_human_approval: true,
      approved: false,
      blocked_reason: 'dry-run mode does not execute real actions'
    },
    next_action_suggestion: 'Review the dry-run plan before any real execution.',
    error: null
  }
}];

const agentOutput = $json || {};

let taskInput = {};
try {
  taskInput = $('Task Validator').item.json || {};
} catch (error) {
  taskInput = {};
}

let promptInput = {};
try {
  promptInput = $('Prompt Builder').item.json || {};
} catch (error) {
  promptInput = {};
}

const context =
  taskInput.context && typeof taskInput.context === 'object'
    ? taskInput.context
    : agentOutput.context && typeof agentOutput.context === 'object'
      ? agentOutput.context
      : {};

const runId =
  taskInput.run_id ||
  agentOutput.run_id ||
  'gd_' + Date.now();

const taskId =
  taskInput.task_id ||
  agentOutput.task_id ||
  'task_' + Date.now();

const goal =
  typeof taskInput.goal === 'string'
    ? taskInput.goal
    : typeof agentOutput.goal === 'string'
      ? agentOutput.goal
      : '';

const criteria = Array.isArray(taskInput.criteria)
  ? taskInput.criteria
  : Array.isArray(agentOutput.criteria)
    ? agentOutput.criteria
    : [];

const iteration =
  Number.isInteger(taskInput.iteration)
    ? taskInput.iteration
    : Number.isInteger(agentOutput.iteration)
      ? agentOutput.iteration
      : 1;

const artifacts = Array.isArray(agentOutput.artifacts)
  ? agentOutput.artifacts
  : [];

const knownIssues = Array.isArray(agentOutput.known_issues)
  ? agentOutput.known_issues
  : [];

const evidence = Array.isArray(agentOutput.evidence)
  ? agentOutput.evidence
  : [];

const provider =
  agentOutput.provider && typeof agentOutput.provider === 'object'
    ? agentOutput.provider
    : null;

const safety =
  agentOutput.safety && typeof agentOutput.safety === 'object'
    ? agentOutput.safety
    : null;

const dryRunPlan =
  agentOutput.dry_run_plan && typeof agentOutput.dry_run_plan === 'object'
    ? agentOutput.dry_run_plan
    : null;

const modeWarnings = Array.isArray(promptInput.mode_warnings)
  ? promptInput.mode_warnings
  : [];

return [
  {
    json: {
      ...taskInput,
      ...agentOutput,

      run_id: runId,
      task_id: taskId,
      goal,
      criteria,
      context,
      iteration,
      requested_provider_mode: promptInput.requested_provider_mode || taskInput.provider_mode || 'mock',
      provider_mode: promptInput.provider_mode || taskInput.provider_mode || 'mock',
      agent_mode: promptInput.agent_mode || taskInput.agent_mode || 'mock',
      mode_warnings: modeWarnings,

      agent_result: {
        run_id: runId,
        task_id: taskId,
        status: agentOutput.status || 'mock_completed',
        summary: agentOutput.summary || 'Mock agent execution completed.',
        artifacts,
        known_issues: knownIssues,
        evidence,
        ...(provider ? { provider } : {}),
        ...(safety ? { safety } : {}),
        ...(dryRunPlan ? { dry_run_plan: dryRunPlan } : {}),
      },

      execution_log: {
        logged_at: new Date().toISOString(),
        summary: agentOutput.summary || 'Mock agent execution completed.',
        artifact_count: artifacts.length,
        issue_count: knownIssues.length,
        criteria_count: criteria.length,
        provider_mode: promptInput.provider_mode || taskInput.provider_mode || 'mock',
        mode_warnings: modeWarnings,
      },
    },
  },
];
